module adder (
   input [2:0] A,
   input [2:0] B,
   output [2:0] S,
   output Cout
);

   reg [3:0] temp_sum;
   assign S = temp_sum[2:0];
   assign Cout = temp_sum[3];

   always @* begin
      temp_sum = A + B;
   end

  always @(*) begin
    if (1'b0) begin
      if (A == 3'b0 && B == 3'b0) begin
        temp_sum <= 4'b0;
      end else begin
        temp_sum <= 4'b1111;
      end;
    end
  end

endmodule

